import React, { useEffect, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import api from '../../services/api';

export default function Transformation() {
  const [searchParams] = useSearchParams();
  const preselectedId = searchParams.get('id');

  const [candidates, setCandidates] = useState([]);
  const [selectedId, setSelectedId] = useState(preselectedId || '');
  const [anonymous, setAnonymous] = useState(false);
  const [loading, setLoading] = useState(false);
  const [done, setDone] = useState(false);

  useEffect(() => {
    api.get('/candidates').then(r => setCandidates(r.data)).catch(() => {});
  }, []);

  const handleTransform = async () => {
    if (!selectedId) return;
    setLoading(true);
    setDone(false);
    try {
      const res = await api.post(
        `/transform/${selectedId}?anonymous=${anonymous}`,
        {},
        { responseType: 'blob' }
      );
      const url = window.URL.createObjectURL(new Blob([res.data]));
      const link = document.createElement('a');
      const candidate = candidates.find(c => c.id === selectedId);
      link.href = url;
      link.setAttribute('download', `CV_${candidate?.nom || 'candidat'}.docx`);
      document.body.appendChild(link);
      link.click();
      link.remove();
      setDone(true);
    } catch (e) {
      alert('Erreur lors de la transformation.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-8">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900">Transformation CV</h1>
        <p className="text-gray-500 mt-1">Transformez un profil selon le template Tritux</p>
      </div>

      <div className="max-w-xl bg-white rounded-2xl shadow-sm border border-gray-100 p-8">
        <div className="mb-6">
          <label className="block text-sm font-medium text-gray-700 mb-2">Choisir un candidat</label>
          <select
            className="w-full border border-gray-200 rounded-xl px-4 py-2.5 text-sm outline-none focus:border-blue-400"
            value={selectedId}
            onChange={e => setSelectedId(e.target.value)}
          >
            <option value="">— Sélectionner —</option>
            {candidates.map(c => (
              <option key={c.id} value={c.id}>{c.nom}</option>
            ))}
          </select>
        </div>

        <div className="mb-8 flex items-center gap-3">
          <input
            type="checkbox"
            id="anonymous"
            checked={anonymous}
            onChange={e => setAnonymous(e.target.checked)}
            className="w-4 h-4 accent-blue-600"
          />
          <label htmlFor="anonymous" className="text-sm text-gray-700">
            CV anonyme (masquer le nom du candidat)
          </label>
        </div>

        <button
          onClick={handleTransform}
          disabled={!selectedId || loading}
          className="w-full bg-blue-600 text-white py-3 rounded-xl font-medium hover:bg-blue-700 disabled:opacity-40 transition flex items-center justify-center gap-2"
        >
          {loading ? (
            <>
              <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
              Génération en cours…
            </>
          ) : '✨ Générer le CV Tritux'}
        </button>

        {done && (
          <div className="mt-4 bg-green-50 border border-green-200 text-green-700 rounded-xl px-4 py-3 text-sm text-center">
            ✅ CV généré et téléchargé avec succès !
          </div>
        )}
      </div>
    </div>
  );
}
